namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeCategory
{
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public string Icon { get; set; } = string.Empty;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private readonly List<RecipeCategory> _categories;

    public RecipeService()
    {
        _categories =
        [
            new() { Name = "Breakfast", Description = "Start your day right", Icon = "🥞" },
            new() { Name = "Lunch", Description = "Midday meals & sandwiches", Icon = "🥗" },
            new() { Name = "Dinner", Description = "Hearty evening dishes", Icon = "🍝" },
            new() { Name = "Desserts", Description = "Sweet treats & baking", Icon = "🍰" },
            new() { Name = "Snacks", Description = "Quick bites & appetizers", Icon = "🧀" },
            new() { Name = "Drinks", Description = "Beverages & smoothies", Icon = "🥤" },
        ];

        _recipes =
        [
            new()
            {
                Id = 1, Title = "Classic Pancakes", Category = "Breakfast",
                Ingredients = "2 cups flour\n2 eggs\n1.5 cups milk\n2 tbsp sugar\n1 tsp baking powder\nPinch of salt",
                Steps = "1. Mix dry ingredients.\n2. Whisk eggs and milk together.\n3. Combine wet and dry.\n4. Cook on greased griddle until bubbles form, then flip.",
                AverageRating = 4.5, RatingCount = 12
            },
            new()
            {
                Id = 2, Title = "Caesar Salad", Category = "Lunch",
                Ingredients = "1 head romaine lettuce\n1/2 cup croutons\n1/4 cup parmesan\nCaesar dressing\nBlack pepper",
                Steps = "1. Wash and chop lettuce.\n2. Toss with dressing.\n3. Top with croutons and parmesan.\n4. Season with pepper.",
                AverageRating = 4.0, RatingCount = 8
            },
            new()
            {
                Id = 3, Title = "Spaghetti Bolognese", Category = "Dinner",
                Ingredients = "400g spaghetti\n500g ground beef\n1 can crushed tomatoes\n1 onion\n3 cloves garlic\nOlive oil\nBasil\nSalt & pepper",
                Steps = "1. Cook spaghetti al dente.\n2. Sauté onion and garlic in oil.\n3. Brown ground beef.\n4. Add tomatoes and simmer 20 min.\n5. Season and serve over pasta.",
                AverageRating = 4.8, RatingCount = 20
            },
            new()
            {
                Id = 4, Title = "Chocolate Chip Cookies", Category = "Desserts",
                Ingredients = "2.25 cups flour\n1 cup butter\n3/4 cup sugar\n2 eggs\n1 tsp vanilla\n2 cups chocolate chips\n1 tsp baking soda",
                Steps = "1. Cream butter and sugar.\n2. Beat in eggs and vanilla.\n3. Mix in flour and baking soda.\n4. Fold in chocolate chips.\n5. Bake at 375°F for 9-11 min.",
                AverageRating = 4.9, RatingCount = 30
            },
        ];
    }

    public List<RecipeCategory> GetCategories() => _categories;

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Count > 0 ? _recipes.Max(r => r.Id) + 1 : 1;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetRecipeById(recipeId);
        if (recipe is null || stars < 1 || stars > 5) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
        recipe.RatingCount++;
        recipe.AverageRating = Math.Round(totalStars / recipe.RatingCount, 1);
    }
}

