@rendermode InteractiveServer
@using RecipeCommunity.Models
@using RecipeCommunity.Services

<PageTitle>Submit a Recipe - Recipe Community</PageTitle>

<div class="container mt-4">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">Submit Recipe</li>
        </ol>
    </nav>

    <h1>📝 Submit a Recipe</h1>
    <p class="text-muted">Share your favorite recipe with the community!</p>

    @if (IsSubmitted)
    {
        <div class="alert alert-success">
            <strong>Success!</strong> Your recipe "@NewRecipe.Title" has been submitted.
            <a href="/recipe/@SubmittedId">View it here</a> or
            <button class="btn btn-link p-0" @onclick="Reset">submit another</button>.
        </div>
    }
    else
    {
        <EditForm Model="NewRecipe" OnValidSubmit="HandleSubmit" FormName="recipeForm">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger" />

            <div class="mb-3">
                <label for="title" class="form-label">Recipe Title</label>
                <InputText id="title" class="form-control" @bind-Value="NewRecipe.Title"
                           placeholder="e.g., Grandma's Apple Pie" />
            </div>

            <div class="mb-3">
                <label for="category" class="form-label">Category</label>
                <InputSelect id="category" class="form-select" @bind-Value="NewRecipe.Category">
                    <option value="">-- Select a category --</option>
                    @foreach (var cat in RecipeService.GetCategories())
                    {
                        <option value="@cat.Name">@cat.Name</option>
                    }
                </InputSelect>
            </div>

            <div class="mb-3">
                <label for="ingredients" class="form-label">Ingredients</label>
                <InputTextArea id="ingredients" class="form-control" rows="5"
                               @bind-Value="NewRecipe.Ingredients"
                               placeholder="List each ingredient on a new line" />
            </div>

            <div class="mb-3">
                <label for="steps" class="form-label">Steps</label>
                <InputTextArea id="steps" class="form-control" rows="6"
                               @bind-Value="NewRecipe.Steps"
                               placeholder="Describe each step on a new line" />
            </div>

            <button type="submit" class="btn btn-success btn-lg"
                    disabled="@(string.IsNullOrWhiteSpace(NewRecipe.Title) || string.IsNullOrWhiteSpace(NewRecipe.Category))">
                Submit Recipe
            </button>
        </EditForm>
    }
</div>

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private Recipe NewRecipe { get; set; } = new();
    private bool IsSubmitted { get; set; }
    private int SubmittedId { get; set; }

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(NewRecipe.Title) || string.IsNullOrWhiteSpace(NewRecipe.Category))
            return;

        RecipeService.AddRecipe(NewRecipe);
        SubmittedId = NewRecipe.Id;
        IsSubmitted = true;
    }

    private void Reset()
    {
        NewRecipe = new();
        IsSubmitted = false;
    }
}

