                <label for="title" class="form-label">Recipe Title</label>
                <InputText id="title" class="form-control" @bind-Value="NewRecipe.Title"
                           placeholder="e.g., Grandma's Apple Pie" />
            </div>

            <div class="mb-3">
                <label for="category" class="form-label">Category</label>
                <InputSelect id="category" class="form-select" @bind-Value="NewRecipe.Category">
                    <option value="">-- Select a category --</option>
                    @foreach (var cat in RecipeService.GetCategories())
                    {
                        <option value="@cat.Name">@cat.Name</option>
                    }
                </InputSelect>
            </div>

            <div class="mb-3">
                <label for="ingredients" class="form-label">Ingredients</label>
                <InputTextArea id="ingredients" class="form-control" rows="5"
                               @bind-Value="NewRecipe.Ingredients"
                               placeholder="List each ingredient on a new line" />
            </div>

